// @hoge1e3/dom-ref
import {update} from "@hoge1e3/dom-updater";
const sym_events="__events";
export function r(ref,render){
  const dom=render(ref.value);
  const events=(
    r[sym_events]=
    r[sym_events]||
    new Set());
  const id=dom.id;
  if(!id)throw new Error("id must be specified");
  if(!events.has(id)){
    ref.on("change",(value)=>{
      update(null,
      render(ref.value));
    });
  }
  return dom;
}